sql:
SELECT listings.name, hosts.host_name
FROM listings
INNER JOIN hosts ON listings.host_id = hosts.host_id;

SELECT listing_id, name, host_id, room_type, price, rating, neighbourhood_full
FROM listings
WHERE neighbourhood_full = 'Manhattan' AND rating >= 4.5;

SELECT h.host_name, l.name AS listing_name, l.neighbourhood_full AS neighbourhood
FROM hosts h
INNER JOIN listings l ON h.host_id = l.host_id;

SELECT l.name AS listing_name, h.host_name
FROM listings l
JOIN hosts h ON l.host_id = h.host_id;

SELECT hosts.host_name
FROM hosts
JOIN listings ON hosts.host_id = listings.host_id
WHERE listings.rating = (
    SELECT MAX(rating) FROM listings
);

SELECT DISTINCT g.guest_id, g.guest_name
FROM guests g
JOIN reviews r ON g.guest_id = r.guest_id;

external_knowledge:
- 'kind of accommodations' refers to 'room_type', such as Private room, Entire home/apt;
- 'each area' refers to 'neighbourhood_full' indicating the full name of the neighbourhood where a listing is located;
- 'typical cost per night' indicates the average price of listings for each combination of neighbourhood and room type.

- 'captains of the vessel' metaphorically refers to 'hosts';
- 'charted the most voyages' metaphorically refers to 'hosted the most listings';
- 'top ten seafarers' metaphorically refers to 'top ten hosts with the most listings';
- 'number of their voyages' metaphorically refers to 'number of listings hosted'.

sql:
SELECT l.listing_id, l.neighbourhood_full, l.host_id
FROM listings l
WHERE l.rating > (SELECT AVG(rating) FROM listings);

SELECT DISTINCT listing_id, name
FROM listings
WHERE rating >= 4.8 AND neighbourhood_full = 'Bronx';
